const recebido = $input.first().json ?? {};
const input = recebido.body && typeof recebido.body === 'object'
  ? recebido.body
  : recebido;

const action = String(
  input.action
  ?? input.acao_agendamento
  ?? ''
).trim().toUpperCase();

if (!['GERAR_OPCOES', 'AGENDAR', 'REAGENDAR'].includes(action)) {
  throw new Error(
    `action inválida: "${action}". Use GERAR_OPCOES, AGENDAR ou REAGENDAR.`
  );
}

const candidatoId = Number(
  input.candidato_id
  ?? input.id
);

if (!Number.isInteger(candidatoId) || candidatoId <= 0) {
  throw new Error(
    `candidato_id inválido: ${input.candidato_id ?? input.id}`
  );
}

const opcaoNumero = Number(
  input.opcao_numero
  ?? input.opcao_horario_escolhida
  ?? 0
);

if (action === 'AGENDAR' && ![1, 2, 3].includes(opcaoNumero)) {
  throw new Error(
    'Para AGENDAR, opcao_numero precisa ser 1, 2 ou 3.'
  );
}

return [{
  json: {
    action,
    candidato_id: candidatoId,
    opcao_numero: action === 'AGENDAR' ? opcaoNumero : null,
    calendar_id: String(
      input.calendar_id
      || 'ec7f0c6eb99778cac22b9a9aefec9e648e8ba5519172b6fc45ab03f938948c7f@group.calendar.google.com'
    ),
    timezone: String(
      input.timezone || 'America/Sao_Paulo'
    ),
    session: String(
      input.session || 'whats_junior'
    ),
    recrutadora_telefone: String(
      input.recrutadora_telefone || '5511951558547'
    ).replace(/\D/g, ''),
    motivo_regeneracao: String(input.motivo_regeneracao || '')
  }
}];

const d = $input.first().json;
const data = new Intl.DateTimeFormat('pt-BR', {
  timeZone: d.timezone || 'America/Sao_Paulo',
  weekday: 'long',
  day: '2-digit',
  month: '2-digit',
  year: 'numeric',
  hour: '2-digit',
  minute: '2-digit'
}).format(new Date(d.entrevista_inicio));

return [{
  json: {
    ok: true,
    status: 'JA_AGENDADA',
    candidato_id: d.candidato_id,
    telefone: d.telefone,
    session: d.session,
    inicio: d.entrevista_inicio,
    fim: d.entrevista_fim,
    meet_link: d.entrevista_meet_link || '',
    google_event_url: d.entrevista_google_event_url || '',
    mensagem_whatsapp:
      `Sua entrevista já está agendada. Abaixo estão os dados para consulta. ✅\n\n` +
      `📅 ${data}\n` +
      `💻 Google Meet\n` +
      `${d.entrevista_meet_link || d.entrevista_google_event_url || ''}\n\n` +
      `Entre no link com aproximadamente 5 minutos de antecedência.`
  }
}];

const d = $input.first().json;
const now = new Date();
const SLOT_MS = 20 * 60 * 1000;
const earliestMs = Math.ceil((now.getTime() + 60 * 60 * 1000) / SLOT_MS) * SLOT_MS;
const latestMs = now.getTime() + 30 * 24 * 60 * 60 * 1000;

return [{
  json: {
    ...d,
    busca_inicio: new Date(earliestMs).toISOString(),
    busca_fim: new Date(latestMs).toISOString(),
    duracao_minutos: 20,
    motivo_regeneracao: d.motivo_regeneracao || ''
  }
}];

const base = $('Preparar janela de busca').first().json;
const eventos = $input.all()
  .map(item => item.json)
  .filter(item => item && Object.keys(item).length);

const timezone = base.timezone || 'America/Sao_Paulo';
const SLOT_MINUTES = 20;
const SLOT_MS = SLOT_MINUTES * 60 * 1000;
const agoraMaisUmaHora = Date.now() + 60 * 60 * 1000;
const limiteBusca = new Date(base.busca_fim).getTime();

function eventDate(value) {
  if (!value) return null;
  if (typeof value === 'string') return new Date(value);
  if (value.dateTime) return new Date(value.dateTime);
  if (value.date) return new Date(`${value.date}T00:00:00-03:00`);
  return null;
}

const ocupados = eventos
  .filter(e => String(e.status || '').toLowerCase() !== 'cancelled')
  .filter(e => String(e.transparency || '').toLowerCase() !== 'transparent')
  .map(e => {
    const inicio = eventDate(e.start);
    const fim = eventDate(e.end);
    return inicio && fim ? [inicio.getTime(), fim.getTime()] : null;
  })
  .filter(Boolean);

function partsAt(date, zone) {
  const parts = new Intl.DateTimeFormat('en-CA', {
    timeZone: zone,
    year: 'numeric', month: '2-digit', day: '2-digit',
    hour: '2-digit', minute: '2-digit', second: '2-digit',
    hourCycle: 'h23'
  }).formatToParts(date);
  return Object.fromEntries(parts.map(part => [part.type, part.value]));
}

function localToUtc(dateString, hour, minute, zone) {
  const [year, month, day] = dateString.split('-').map(Number);
  let guess = Date.UTC(year, month - 1, day, hour, minute, 0);

  for (let i = 0; i < 3; i++) {
    const p = partsAt(new Date(guess), zone);
    const represented = Date.UTC(
      Number(p.year), Number(p.month) - 1, Number(p.day),
      Number(p.hour), Number(p.minute), Number(p.second)
    );
    const target = Date.UTC(year, month - 1, day, hour, minute, 0);
    guess += target - represented;
  }

  return new Date(guess);
}

const dateKeyFormatter = new Intl.DateTimeFormat('en-CA', {
  timeZone: timezone,
  year: 'numeric', month: '2-digit', day: '2-digit'
});
const weekdayFormatter = new Intl.DateTimeFormat('en-US', {
  timeZone: timezone,
  weekday: 'short'
});
const displayFormatter = new Intl.DateTimeFormat('pt-BR', {
  timeZone: timezone,
  weekday: 'long',
  day: '2-digit',
  month: '2-digit',
  hour: '2-digit',
  minute: '2-digit',
  hourCycle: 'h23'
});

function overlaps(start, end) {
  return ocupados.some(([busyStart, busyEnd]) => start < busyEnd && end > busyStart);
}

const opcoes = [];
const primeiroDia = new Date();

for (let deslocamento = 0; deslocamento <= 30 && opcoes.length < 3; deslocamento++) {
  const referencia = new Date(primeiroDia.getTime() + deslocamento * 24 * 60 * 60 * 1000);
  const dataLocal = dateKeyFormatter.format(referencia);
  const weekday = weekdayFormatter.format(localToUtc(dataLocal, 12, 0, timezone));

  if (!['Mon', 'Tue', 'Wed', 'Thu', 'Fri'].includes(weekday)) continue;

  // Último início permitido: 17:40, para a entrevista terminar às 18:00.
  for (let minutos = 8 * 60; minutos <= 17 * 60 + 40 && opcoes.length < 3; minutos += SLOT_MINUTES) {
    const hora = Math.floor(minutos / 60);
    const minuto = minutos % 60;
    const inicio = localToUtc(dataLocal, hora, minuto, timezone);
    const fim = new Date(inicio.getTime() + SLOT_MS);

    if (inicio.getTime() < agoraMaisUmaHora) continue;
    if (fim.getTime() > limiteBusca) continue;
    if (overlaps(inicio.getTime(), fim.getTime())) continue;

    const verificacao = partsAt(inicio, timezone);
    const minutoLocal = Number(verificacao.hour) * 60 + Number(verificacao.minute);
    const fimLocal = partsAt(new Date(fim.getTime() - 1), timezone);
    const minutoFimLocal = Number(fimLocal.hour) * 60 + Number(fimLocal.minute) + 1;

    if (minutoLocal < 8 * 60 || minutoFimLocal > 18 * 60) continue;

    opcoes.push({
      opcao: opcoes.length + 1,
      inicio: inicio.toISOString(),
      fim: fim.toISOString(),
      texto: displayFormatter.format(inicio)
    });
  }
}

const lote = `op-${base.candidato_id}-${Date.now()}`;
const prefixo = base.motivo_regeneracao === 'HORARIO_OCUPADO'
  ? 'O horário escolhido acabou de ser ocupado. Separei três novas opções disponíveis:\n\n'
  : base.motivo_regeneracao === 'OPCAO_INVALIDA'
    ? 'Essas opções venceram ou não consegui identificar a escolha. Separei três novas opções:\n\n'
    : base.motivo_regeneracao === 'SOLICITADO_PELO_CANDIDATO'
      ? 'Claro! Separei três novas opções disponíveis:\n\n'
      : base.motivo_regeneracao === 'REAGENDAMENTO'
        ? 'O horário anterior foi liberado. Separei três novas opções para o reagendamento:\n\n'
        : 'Você gostaria de marcar uma entrevista on-line pelo Google Meet? Estas são as opções disponíveis:\n\n';

let mensagem;
if (opcoes.length === 3) {
  mensagem =
    prefixo +
    opcoes.map(o => `${o.opcao}. ${o.texto}`).join('\n') +
    '\n\nA entrevista dura cerca de 20 minutos. Os horários são entre 08h e 18h. Responda com 1, 2 ou 3.';
} else {
  mensagem =
    'Sua triagem está aprovada, mas não encontrei três horários livres entre 08h e 18h no momento. ' +
    'A equipe de recrutamento entrará em contato para combinar a entrevista.';
}

return [{
  json: {
    ...base,
    lote,
    opcoes,
    encontrou_tres: opcoes.length === 3,
    expira_em: new Date(Date.now() + 24 * 60 * 60 * 1000).toISOString(),
    mensagem_whatsapp: mensagem
  }
}];

const d = $input.first().json;
const inicio = new Date(d.inicio);
const fim = new Date(d.fim);

function fnv1a(text, seed = 2166136261) {
  let hash = seed >>> 0;
  for (let i = 0; i < text.length; i++) {
    hash ^= text.charCodeAt(i);
    hash = Math.imul(hash, 16777619) >>> 0;
  }
  return hash.toString(16).padStart(8, '0');
}

const chave = `${d.candidato_id}|${inicio.toISOString()}|${d.vaga}`;
const eventId = `dlgreen${fnv1a(chave)}${fnv1a(chave, 2246822519)}`;

return [{
  json: {
    ...d,
    event_id: eventId,
    titulo: `Entrevista - ${d.nome || 'Candidato'} - ${d.vaga}`,
    descricao: [
      `Candidato: ${d.nome || 'Não informado'}`,
      `Candidato ID: ${d.candidato_id}`,
      `Telefone: ${d.telefone || 'Não informado'}`,
      `Vaga: ${d.vaga}`,
      '',
      `Apresentação: ${d.apresentacao_profissional || 'Não registrada'}`,
      `Perfil profissional percebido: ${d.personalidade_resumo || 'Não analisado'}`,
      '',
      'Agendamento criado automaticamente pelo processo seletivo da DL Green.'
    ].join('\n')
  }
}];

const evento = $input.first().json;
const d = $('Preparar evento da entrevista').first().json;

const meet =
  evento.hangoutLink
  || evento.conferenceData?.entryPoints?.find(p => p.entryPointType === 'video')?.uri
  || '';

const data = new Intl.DateTimeFormat('pt-BR', {
  timeZone: d.timezone || 'America/Sao_Paulo',
  weekday: 'long',
  day: '2-digit',
  month: '2-digit',
  year: 'numeric',
  hour: '2-digit',
  minute: '2-digit'
}).format(new Date(d.inicio));

const tags = Array.isArray(d.personalidade_tags)
  ? d.personalidade_tags.join(', ')
  : '';

const mensagemCandidato =
  `Entrevista agendada com sucesso! ✅\n\n` +
  `📅 ${data}\n` +
  `⏱️ Duração aproximada: 20 minutos\n` +
  `💻 Google Meet\n\n` +
  `Link para participar:\n${meet || evento.htmlLink || ''}\n\n` +
  `Entre no link com aproximadamente 5 minutos de antecedência. ` +
  `Caso precise cancelar ou reagendar, avise por aqui.`;

const mensagemRecrutadora =
  `📌 Nova entrevista agendada\n\n` +
  `Candidato(a): ${d.nome || 'Não informado'}\n` +
  `WhatsApp: ${d.telefone || 'Não informado'}\n` +
  `Vaga: ${d.vaga}\n` +
  `Data e horário: ${data}\n` +
  `Duração: 20 minutos\n\n` +
  `Apresentação: ${d.apresentacao_profissional || 'Não registrada'}\n\n` +
  `Perfil profissional percebido: ${d.personalidade_resumo || 'Não analisado'}` +
  (tags ? `\nCaracterísticas: ${tags}` : '') +
  `\n\nGoogle Meet:\n${meet || evento.htmlLink || ''}`;

return [{
  json: {
    ...d,
    google_event_id: evento.id || d.event_id,
    google_event_url: evento.htmlLink || '',
    meet_link: meet,
    mensagem_whatsapp: mensagemCandidato,
    mensagem_recrutadora: mensagemRecrutadora
  }
}];

const atual = $input.first().json ?? {};
let origem = atual;

function tentar(nome) {
  try {
    return $(nome).first().json ?? null;
  } catch {
    return null;
  }
}

const entrevista = tentar('Persistir entrevista');
const opcoes = tentar('Persistir opções e mensagem');
const existente = tentar('Retorno entrevista existente');
const carregado = tentar('Carregar candidato e vaga');

if (entrevista?.mensagem_whatsapp) {
  origem = entrevista;
} else if (opcoes?.mensagem_whatsapp) {
  origem = opcoes;
} else if (existente?.mensagem_whatsapp) {
  origem = existente;
}

return [{
  json: {
    ...origem,
    candidato_id: Number(
      origem.candidato_id
      ?? carregado?.candidato_id
    ),
    telefone: String(
      origem.telefone
      ?? carregado?.telefone
      ?? ''
    ).replace(/\D/g, ''),
    session: String(
      origem.session
      ?? carregado?.session
      ?? 'whats_junior'
    ),
    mensagem_whatsapp: String(
      origem.mensagem_whatsapp
      ?? origem.mensagem
      ?? ''
    ).trim()
  }
}];

const d = $input.first().json;

if (!d.entrevista_id) {
  return [{
    json: {
      ...d,
      possui_evento_anterior: false,
      google_event_id_anterior: '',
      calendar_id_anterior: d.calendar_id,
      motivo_regeneracao: 'REAGENDAMENTO'
    }
  }];
}

return [{
  json: {
    ...d,
    possui_evento_anterior: Boolean(d.entrevista_google_event_id),
    google_event_id_anterior: String(d.entrevista_google_event_id || ''),
    calendar_id_anterior: String(d.entrevista_calendar_id || d.calendar_id),
    motivo_regeneracao: 'REAGENDAMENTO'
  }
}];
